// --- PARAMETRI ---
float zoom = 1.0;       // Collegato alla densità/zoom dell'UI
vec2 center = vec2(-0.5, 0.0); // Centro del frattale
int max_iter = 100;     // Qualità del dettaglio
// --- MAPPATURA COORDINATE ---
// Trasformiamo u,v (0.0 - 1.0) nel piano complesso
// Moltiplichiamo per 3.0 per avere un'inquadratura iniziale classica.
// Dividiamo per 'zoom' per ingrandire.
vec2 c = (vec2(u, v) - 0.5) * (3.0 / zoom) + center;
// --- LOGICA MANDELBROT (Z = Z^2 + C) ---
vec2 z = vec2(0.0);
int iter = 0;
for (int i = 0; i < 100; i++) { // Loop fisso per GLSL (usa max_iter per il break)
    if (i >= max_iter) break;
    // Ottimizzazione: se la distanza al quadrato > 4, è scappato
    if (dot(z, z) > 4.0) break;
    // Calcolo numero complesso: (x + iy)^2 + c
    // Parte Reale: x^2 - y^2 + cx
    // Parte Immaginaria: 2xy + cy
    float x = (z.x * z.x - z.y * z.y) + c.x;
    float y = (2.0 * z.x * z.y) + c.y;
    z = vec2(x, y);
    iter++;
}
// --- COLORAZIONE ---
// Normalizziamo le iterazioni tra 0.0 e 1.0
float t = float(iter) / float(max_iter);
// Usiamo una radice quadrata (pow 0.5) per rendere il gradiente più visibile
// e meno "tutto nero" ai bordi.
t = sqrt(t);
// Mix tra i colori dell'utente
// t=0 (esterno immediato) -> Colore 1
// t=1 (interno insieme)   -> Colore 2
return mix(u_col1, u_col2, t);

